import pika
import subprocess
import json
import shlex
import os
import sys
from typing import Optional, List
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class SecureJobConsumer:
    def __init__(
        self,
        host: str = 'localhost',
        queue_name: str = 'job_queue',
        allowed_commands: Optional[List[str]] = None,
        allowed_paths: Optional[List[str]] = None,
        max_execution_time: int = 300
    ):
        self.host = host
        self.queue_name = queue_name
        self.max_execution_time = max_execution_time
        
        self.allowed_commands = allowed_commands or [
            'echo',
            'ls',
            'cat',
            'grep',
            'wc',
            'sort',
            'uniq',
            'head',
            'tail'
        ]
        
        self.allowed_paths = allowed_paths or ['/tmp/jobs', '/var/jobs']
        
        self.dangerous_chars = ['&', '|', ';', '>', '<', '`', '$', '(', ')', '{', '}', '[', ']', '\n', '\r']
        
    def validate_command(self, command: str) -> bool:
        if not command or not isinstance(command, str):
            logger.error("Invalid command: empty or not a string")
            return False
        
        command = command.strip()
        
        for char in self.dangerous_chars:
            if char in command:
                logger.error(f"Dangerous character detected: {char}")
                return False
        
        try:
            parts = shlex.split(command)
        except ValueError as e:
            logger.error(f"Command parsing failed: {e}")
            return False
        
        if not parts:
            logger.error("Empty command after parsing")
            return False
        
        base_command = os.path.basename(parts[0])
        
        if base_command not in self.allowed_commands:
            logger.error(f"Command not in allowlist: {base_command}")
            return False
        
        for part in parts[1:]:
            if part.startswith('-'):
                continue
            
            if os.path.isabs(part) or '..' in part:
                is_allowed = False
                try:
                    abs_path = os.path.abspath(part)
                    for allowed_path in self.allowed_paths:
                        if abs_path.startswith(os.path.abspath(allowed_path)):
                            is_allowed = True
                            break
                    
                    if not is_allowed:
                        logger.error(f"Path not in allowed directories: {part}")
                        return False
                except Exception as e:
                    logger.error(f"Path validation error: {e}")
                    return False
        
        return True
    
    def execute_command(self, command: str) -> dict:
        if not self.validate_command(command):
            return {
                'success': False,
                'error': 'Command validation failed',
                'stdout': '',
                'stderr': ''
            }
        
        try:
            parts = shlex.split(command)
            
            result = subprocess.run(
                parts,
                capture_output=True,
                text=True,
                timeout=self.max_execution_time,
                shell=False,
                check=False,
                env={'PATH': '/usr/bin:/bin'},
                cwd='/tmp'
            )
            
            return {
                'success': result.returncode == 0,
                'returncode': result.returncode,
                'stdout': result.stdout,
                'stderr': result.stderr,
                'error': None
            }
            
        except subprocess.TimeoutExpired:
            logger.error(f"Command timed out: {command}")
            return {
                'success': False,
                'error': 'Command execution timed out',
                'stdout': '',
                'stderr': ''
            }
        except Exception as e:
            logger.error(f"Command execution failed: {e}")
            return {
                'success': False,
                'error': str(e),
                'stdout': '',
                'stderr': ''
            }
    
    def process_message(self, ch, method, properties, body):
        try:
            message = body.decode('utf-8')
            logger.info(f"Received message: {message[:100]}")
            
            try:
                msg_data = json.loads(message)
                command = msg_data.get('command', '')
            except json.JSONDecodeError:
                command = message
            
            result = self.execute_command(command)
            
            if result['success']:
                logger.info(f"Command executed successfully: {command[:50]}")
                ch.basic_ack(delivery_tag=method.delivery_tag)
            else:
                logger.error(f"Command failed: {result.get('error', 'Unknown error')}")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                
        except Exception as e:
            logger.error(f"Message processing error: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    
    def start(self):
        try:
            connection = pika.BlockingConnection(
                pika.ConnectionParameters(host=self.host)
            )
            channel = connection.channel()
            
            channel.queue_declare(queue=self.queue_name, durable=True)
            
            channel.basic_qos(prefetch_count=1)
            
            channel.basic_consume(
                queue=self.queue_name,
                on_message_callback=self.process_message
            )
            
            logger.info(f"Started consuming from queue: {self.queue_name}")
            channel.start_consuming()
            
        except KeyboardInterrupt:
            logger.info("Consumer stopped by user")
            sys.exit(0)
        except Exception as e:
            logger.error(f"Consumer error: {e}")
            sys.exit(1)


if __name__ == '__main__':
    consumer = SecureJobConsumer(
        host='localhost',
        queue_name='job_queue',
        allowed_commands=['echo', 'ls', 'cat', 'grep', 'wc'],
        allowed_paths=['/tmp/jobs'],
        max_execution_time=60
    )
    
    consumer.start()